// ============================================================
// Utility functions
// ============================================================

function generateRefreshToken() {
  return crypto.randomBytes(64).toString('hex');
}

function generateAuthorizationCode() {
  return crypto.randomBytes(32).toString('hex');
}

function generateAccessToken(payload) {
  return jwt.sign(payload, CONFIG.ACCESS_TOKEN_SECRET, {
    expiresIn: CONFIG.ACCESS_TOKEN_EXPIRY,
    issuer: 'oauth2-server',
    jwtid: uuidv4(),
  });
}

function verifyAccessToken(token) {
  try {
    return jwt.verify(token, CONFIG.ACCESS_TOKEN_SECRET, { issuer: 'oauth2-server' });
  } catch (err) {
    return null;
  }
}

function authenticateClient(req) {
  let clientId, clientSecret;

  // Check Authorization header (Basic auth)
  const authHeader = req.headers.authorization;
  if (authHeader && authHeader.startsWith('Basic ')) {
    const decoded = Buffer.from(authHeader.slice(6), 'base64').toString('utf-8');
    const parts = decoded.split(':');
    clientId = decodeURIComponent(parts[0]);
    clientSecret = decodeURIComponent(parts.slice(1).join(':'));
  } else {
    // Check body params
    clientId = req.body.client_id;
    clientSecret = req.body.client_secret;
  }

  if (!clientId || !clientSecret) {
    return null;
  }

  const client = clients.get(clientId);
  if (!client || client.clientSecret !== clientSecret) {
    return null;
  }

  return client;
}

// ============================================================
// Redis helpers for refresh tokens
// ============================================================

async function storeRefreshToken(token, data) {
  const key = `refresh_token:${token}`;
  await redis.set(key, JSON.stringify(data), 'EX', CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS);
  // Also maintain a set of refresh tokens per user for management
  const userKey = `user_refresh_tokens:${data.userId}`;
  await redis.sadd(userKey, token);
  await redis.expire(userKey, CONFIG.REFRESH_TOKEN_EXPIRY_SECONDS);
}

async function getRefreshToken(token) {
  const key = `refresh_token:${token}`;
  const data = await redis.get(key);
  if (!data) return null;
  return JSON.parse(data);
}

async function revokeRefreshToken(token) {
  const data = await getRefreshToken(token);
  const key = `refresh_token:${token}`;
  await redis.del(key);
  if (data) {
    const userKey = `user_refresh_tokens:${data.userId}`;
    await redis.srem(userKey, token);
  }
}

async function revokeAllUserRefreshTokens(userId) {
  const userKey = `user_refresh_tokens:${userId}`;
  const tokens = await redis.smembers(userKey);
  if (tokens.length > 0) {
    const pipeline = redis.pipeline();
    for (const token of tokens) {
      pipeline.del(`refresh_token:${token}`);
    }
    pipeline.del(userKey);
    await pipeline.exec();
  }
}

async function updateRefreshTokenLastUsed(token, data) {
  // Update last_used timestamp without changing the TTL significantly
  // We keep the original expiry by recalculating remaining TTL
  const key = `refresh_token:${token}`;
  const ttl = await redis.ttl(key);
  if (ttl > 0) {
    data.lastUsedAt = new Date().toISOString();
    data.useCount = (data.useCount || 0) + 1;
    await redis.set(key, JSON.stringify(data), 'EX', ttl);
  }
}

