app.post('/authorize', async (req, res) => {
  const { response_type, client_id, redirect_uri, scope, state, username, password } = req.body;

  if (response_type !== 'code') {
    return res.status(400).json({
      error: 'unsupported_response_type',
    });
  }

  const client = clients.get(client_id);
  if (!client) {
    return res.status(400).json({ error: 'invalid_client' });
  }

  const effectiveRedirectUri = redirect_uri || client.redirectUris[0];
  if (!client.redirectUris.includes(effectiveRedirectUri)) {
    return res.status(400).json({ error: 'invalid_request', error_description: 'Invalid redirect_uri.' });
  }

  // Authenticate user
  let authenticatedUser = null;
  for (const [, user] of users) {
    if (user.username === username) {
      const valid = await bcrypt.compare(password, user.passwordHash);
      if (valid) {
        authenticatedUser = user;
      }
      break;
    }
  }

  if (!authenticatedUser) {
    return res.status(401).send(`
      <html><body>
        <h1>Authentication Failed</h1>
        <p>Invalid username or password.</p>
        <a href="/authorize?response_type=${response_type}&client_id=${client_id}&redirect_uri=${encodeURIComponent(effectiveRedirectUri)}&scope=${scope || ''}&state=${state || ''}">Try again</a>
      </body></html>
    `);
  }

  // Generate authorization code
  const code = generateAuthorizationCode();
  const codeData = {
    code,
    clientId: client_id,
    userId: authenticatedUser.id,
    redirectUri: effectiveRedirectUri,
    scope: scope || '',
    createdAt: Date.now(),
    expiresAt: Date.now() + CONFIG.AUTHORIZATION_CODE_EXPIRY * 1000,
  };

  // Store in Redis with short TTL
  await redis.set(`auth_code:${code}`, JSON.stringify(codeData), 'EX', CONFIG.AUTHORIZATION_CODE_EXPIRY);

  // Redirect back to client
  const redirectUrl = new URL(effectiveRedirectUri);
  redirectUrl.searchParams.set('code', code);
  if (state) {
    redirectUrl.searchParams.set('state', state);
  }

  res.redirect(redirectUrl.toString());
});

